// import { Link, NavLink } from 'react-router-dom';
import useAxios from 'axios-hooks';
import '../App.css';
// import { Component } from 'react';
import '../../node_modules/bootstrap/dist/css/bootstrap.css'
// import BootstrapTable from 'react-bootstrap-table-next';

function Sing() {
    const [{ data, loading, error }, refetch] = useAxios('http://127.0.0.1:5000/sings');

    if (loading) {
        return(
            <div className='loading'>
                <p>Загрузка данных...</p>
            </div>
        );
    }

    if (error) {
        return(
            <div className='error'>
                <p>Ошибка:</p>
                <p>{error.message}</p>
                <button onClick={() => refetch()}>
                    Повторный запрос
                </button>
            </div>
        );
    }

    return (
        <div style={{ padding: '20px' }}>
        <h1>Users Table</h1>
        <button 
            onClick={refetch}
            style={{
            padding: '10px 20px',
            marginBottom: '20px',
            backgroundColor: '#007bff',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer'
            }}
        >
            Refresh Data
        </button>

        <pre style={{
                marginTop: '30px',
                backgroundColor: '#f8f9fa',
                padding: '15px',
                borderRadius: '5px',
                fontSize: '14px'
            }}>
                Full API Response:
                {JSON.stringify(data, null, 2)}
        </pre>

        {data && (
            <>
            {/* <div style={{ marginBottom: '10px' }}>
                <p>Total users: {data.total || data.data.length}</p>
                <p>Page: {data.page || 1} of {data.total_pages || 1}</p>
            </div>

            <table style={{
                width: '100%',
                borderCollapse: 'collapse',
                marginTop: '20px',
                boxShadow: '0 0 10px rgba(0,0,0,0.1)'
            }}>
                <thead>
                <tr style={{ backgroundColor: '#faf8f8ff' }}>
                    <th style={{ 
                    padding: '12px', 
                    textAlign: 'left', 
                    borderBottom: '2px solid #e6dee4ff',
                    fontWeight: 'bold'
                    }}>ID</th>
                    <th style={{ 
                    padding: '12px', 
                    textAlign: 'left', 
                    borderBottom: '2px solid #dee2e6',
                    fontWeight: 'bold'
                    }}>name_sing</th>
                </tr>
                </thead>
                <tbody>
                {data.data.map((user) => (
                    <tr key={user.id} style={{
                    borderBottom: '1px solid #dee2e6',
                    transition: 'background-color 0.2s'
                    }}>
                    <td style={{ padding: '12px' }}>{user.id}</td>
                    <td style={{ padding: '12px' }}>{user.name_sing}</td>
                    </tr>
                ))}
                </tbody>
            </table> */}

            <pre style={{
                marginTop: '30px',
                backgroundColor: '#f8f9fa',
                padding: '15px',
                borderRadius: '5px',
                fontSize: '14px'
            }}>
                Full API Response:
                {JSON.stringify(data['items'], null, 2)}
            </pre>
            </>
        )}
        </div>
    );
}

